/**
 * WebSocket Message Envelope Schema
 * Enforces consistent message structure across all WebSocket communication
 * Supports backward compatibility through version negotiation
 */

import type {
  ConnectionNegotiation,
  HeartbeatMessage,
  MessageEnvelope,
} from '@sc-fleet-manager/shared-types';
import Joi from 'joi';

// Re-export types from shared-types for consumer convenience
export type { ConnectionNegotiation, HeartbeatMessage, MessageEnvelope };

/**
 * Envelope validator Joi schema
 */
export const messageEnvelopeSchema = Joi.object<MessageEnvelope>({
  type: Joi.string().required().max(50).description('Message type identifier'),
  version: Joi.number().required().integer().min(1).max(100).description('Schema version'),
  payload: Joi.any().required().description('Typed message payload'),
  timestamp: Joi.string().required().isoDate().description('ISO 8601 timestamp'),
  messageId: Joi.string().optional().uuid().description('Optional message correlation ID'),
});

/**
 * Heartbeat validator
 */
export const heartbeatSchema = Joi.object<HeartbeatMessage>({
  type: Joi.string().required().valid('ping', 'pong'),
  version: Joi.number().required().equal(1),
  payload: Joi.valid(null).required(),
  timestamp: Joi.string().required().isoDate(),
  messageId: Joi.string().optional(),
});

/**
 * Connection negotiation validator
 */
export const negotiationSchema = Joi.object<ConnectionNegotiation>({
  type: Joi.string().required().equal('negotiate'),
  version: Joi.number().required().equal(1),
  payload: Joi.object({
    clientVersion: Joi.number().required().integer().min(1),
    supportedVersions: Joi.array().items(Joi.number().integer().min(1)).required(),
    clientId: Joi.string().optional(),
  }),
  timestamp: Joi.string().required().isoDate(),
});

/**
 * Validate and normalize message envelope
 * @param message - Raw message object
 * @param allowDefault - If true, version defaults to 1 if missing
 * @returns Validated envelope or throws ValidationError
 */
export function validateEnvelope(message: unknown, allowDefault: boolean = false): MessageEnvelope {
  if (allowDefault && typeof message === 'object' && message !== null) {
    const msg = message as Record<string, unknown>;
    if (!('version' in msg)) {
      msg.version = 1;
    }
    if (!('timestamp' in msg)) {
      msg.timestamp = new Date().toISOString();
    }
  }

  const { error, value } = messageEnvelopeSchema.validate(message, {
    abortEarly: false,
    convert: false,
  });

  if (error) {
    throw new Error(`Invalid message envelope: ${error.message}`);
  }

  return value;
}

/**
 * Create a valid heartbeat message
 */
export function createHeartbeat(type: 'ping' | 'pong'): HeartbeatMessage {
  return {
    type,
    version: 1,
    payload: null,
    timestamp: new Date().toISOString(),
  };
}

/**
 * Create a negotiation message
 */
export function createNegotiation(
  clientVersion: number,
  supportedVersions: number[],
  clientId?: string
): ConnectionNegotiation {
  return {
    type: 'negotiate',
    version: 1,
    payload: {
      clientVersion,
      supportedVersions,
      clientId,
    },
    timestamp: new Date().toISOString(),
  };
}
